{
  "version": 1,
  "owner": "broklein",
  "updated_at": "2026-02-17",
  "preferences": {
    "home_dir": {
      "minimal": true,
      "avoid_ad_hoc_files": true,
      "avoid_new_dotfiles_unless_required": true,
      "forbid_zshrc_creation": true,
      "zsh_layout": "XDG under ~/.config/zsh with ~/.zshenv symlink"
    },
    "code": {
      "root": "~/codeWS",
      "policy": "all repo work under ~/codeWS/<Language>/<Project> or ~/codeWS/Projects/<Project>"
    },
    "docs": {
      "root": "~/Documents/OpenClaw",
      "policy": "openclaw-generated docs/audits/reports go to Documents, not workspace roots"
    },
    "tasks": {
      "source_of_truth": "oc-tasks",
      "forbid_progress_md": true,
      "manual": "~/.openclaw/docs/OC-TASKS-MANUAL.md"
    }
  }
}
